PACKAGE_MANAGER="${PACKAGE_MANAGER:-auto}"
BUILD_SCRIPT="${BUILD_SCRIPT:-build}"
TEST_SCRIPT="${TEST_SCRIPT:-test}"
DEPLOY_SCRIPT="${DEPLOY_SCRIPT:-deploy:production}"
